import React, { useState } from "react";

export default function WithdrawScreen({ balance, onWithdraw, setCurrentScreen, showToast }) {
  const [amount, setAmount] = useState("");

  const handleWithdraw = () => {
    const value = parseFloat(amount);
    if (!amount || isNaN(value) || value <= 0) {
      showToast("Enter a valid amount", "error");
      return;
    }
    if (value > balance) {
      showToast("Insufficient balance", "error");
      return;
    }
    onWithdraw(value);
    setAmount("");
    showToast(`Successfully withdrew $${value}`, "success");
    setCurrentScreen("Dashboard"); // go back to dashboard
  };

  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Withdraw Funds</h1>

      <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm space-y-4">
        <p className="text-gray-500">Current balance: ${balance}</p>
        <input
          type="number"
          placeholder="Enter amount"
          className="w-full border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
        />
        <button
          onClick={handleWithdraw}
          className="w-full py-3 bg-red-600 text-white rounded-xl hover:bg-red-700 transition-colors"
        >
          Withdraw
        </button>
      </div>
    </div>
  );
}
